func (t Application) ValueByDiscriminator() (interface{}, error) {
	discriminator, err := t.Discriminator()
	if err != nil {
		return nil, err
	}
	switch discriminator {
	case "agentQueue":
		return t.AsQueueAgentApplication()
	case "agentic":
		return t.AsAgenticApplication()
	case "audioPlayer":
		return t.AsAudioPlayerApplication()
	case "consumerQueue":
		return t.AsQueueConsumerApplication()
	case "inputReader":
		return t.AsInputReaderApplication()
	case "inputReader.v2":
		return t.AsInputReaderV2Application()
	case "promptPlayer":
		return t.AsPromptPlayerApplication()
	case "recording":
		return t.AsRecordingApplication()
	case "simpleMenu":
		return t.AsSimpleMenuApplication()
	case "speechToText":
		return t.AsSpeechToTextApplication()
	case "switchNode":
		return t.AsSwitchNodeApplication()
	case "textToSpeech":
		return t.AsTextToSpeechApplication()
	case "transfer":
		return t.AsTransferApplication()
	default:
		return nil, errors.New("unknown discriminator value: " + discriminator)
	}
}

